// SPDX-License-Identifier: MIT
pragma solidity 0.8.20;

contract FundPoolManager {
    address public owner;
    mapping(address => address) public pools; // pool => rewardToken

    event PoolAdded(address indexed pool, address indexed rewardToken);
    event PoolRemoved(address indexed pool);
    event FundsTransferred(address indexed pool, address indexed to, uint256 amount);
    event FundsRescued(address indexed to, uint256 amount);
    event Received(address indexed sender, uint256 amount);

    error OnlyOwner();
    error OnlyPool();
    error ZeroAddress();
    error PoolNotRegistered();
    error InsufficientBalance();

    modifier onlyOwner() {
        if (msg.sender != owner) revert OnlyOwner();
        _;
    }

    modifier onlyPool() {
        if (pools[msg.sender] == address(0)) revert OnlyPool();
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function addPool(address pool, address rewardToken) external onlyOwner {
        if (pool == address(0) || rewardToken == address(0)) revert ZeroAddress();
        pools[pool] = rewardToken;
        emit PoolAdded(pool, rewardToken);
    }

    function removePool(address pool) external onlyOwner {
        if (pool == address(0)) revert ZeroAddress();
        delete pools[pool];
        emit PoolRemoved(pool);
    }

    function transferTo(address payable to, uint256 amount) external onlyPool {
        if (to == address(0)) revert ZeroAddress();
        if (address(this).balance < amount) revert InsufficientBalance();
        (bool success, ) = to.call{value: amount}("");
        require(success, "Transfer failed");
        emit FundsTransferred(msg.sender, to, amount);
    }

    function rescueFund(address payable to, uint256 amount) external onlyOwner {
        if (to == address(0)) revert ZeroAddress();
        if (address(this).balance < amount) revert InsufficientBalance();
        (bool success, ) = to.call{value: amount}("");
        require(success, "Rescue transfer failed");
        emit FundsRescued(to, amount);
    }

    receive() external payable {
        emit Received(msg.sender, msg.value);
    }
}
